# ── Silence SSL warnings that come with verify=False ─────────────────────────
import urllib3
urllib3.disable_warnings(urllib3.exceptions.InsecureRequestWarning)

import requests
from typing import Optional

# ---------------------------------------------------------------------------
# Config
# ---------------------------------------------------------------------------
_BASE    = "https://api.cricketdata.org/api/v1"
_TIMEOUT = 12
_HEADERS = {"Accept": "application/json", "User-Agent": "cricket-tool/1.0"}


def _get(path: str, params: Optional[dict] = None) -> dict:
    """
    GET helper with verify=False to bypass the SSL EOF bug in Python 3.11
    (SSLEOFError UNEXPECTED_EOF_WHILE_READING) that affects some servers
    when running inside a Docker container.
    """
    try:
        resp = requests.get(
            f"{_BASE}{path}",
            params=params,
            headers=_HEADERS,
            timeout=_TIMEOUT,
            verify=False,
        )
        resp.raise_for_status()
        return resp.json()
    except requests.exceptions.Timeout:
        return {"error": "Request timed out.", "data": []}
    except requests.exceptions.SSLError as e:
        return {"error": f"SSL error: {str(e)[:180]}", "data": []}
    except requests.exceptions.HTTPError as e:
        return {"error": f"HTTP {e.response.status_code}: {e.response.text[:200]}", "data": []}
    except requests.exceptions.RequestException as e:
        return {"error": str(e)[:200], "data": []}
    except Exception as e:
        return {"error": f"Unexpected error: {str(e)[:200]}", "data": []}


# ---------------------------------------------------------------------------
# 1. Live scores
# ---------------------------------------------------------------------------

def get_live_scores() -> dict:
    """
    Fetch all currently live cricket matches.

    Returns
    -------
    dict  { matches: list, count: int }
    """
    raw = _get("/currentMatches")
    if "error" in raw:
        return raw

    matches = []
    for item in raw.get("data", []):
        score_list = item.get("score", [])
        matches.append({
            "match_id":   item.get("id", ""),
            "teams":      item.get("name", ""),
            "score":      ", ".join(score_list) if isinstance(score_list, list) else str(score_list),
            "status":     item.get("status", ""),
            "match_type": item.get("matchType", "").upper(),
        })
    return {"matches": matches, "count": len(matches)}


# ---------------------------------------------------------------------------
# 2. Player stats
# ---------------------------------------------------------------------------

def get_player_stats(player_name: str) -> dict:
    """
    Search for a player and return career batting + bowling stats.

    Parameters
    ----------
    player_name : str  e.g. 'Virat Kohli'
    """
    search_raw = _get("/players", params={"offset": 0, "search": player_name})
    if "error" in search_raw:
        return search_raw

    players = search_raw.get("data", [])
    if not players:
        return {"error": f"No player found matching '{player_name}'."}

    player_id = players[0].get("id", "")
    if not player_id:
        return {"error": "Player found but ID is missing."}

    detail_raw = _get(f"/players/{player_id}", params={"id": player_id})
    if "error" in detail_raw:
        return detail_raw

    d = detail_raw.get("data", {})

    def _s(v):
        return v if v not in (None, "-", "") else "N/A"

    return {
        "name":    _s(d.get("name")),
        "country": _s(d.get("country")),
        "batting": {
            "matches":     _s(d.get("battingStats", {}).get("matches")),
            "innings":     _s(d.get("battingStats", {}).get("inns")),
            "runs":        _s(d.get("battingStats", {}).get("runs")),
            "average":     _s(d.get("battingStats", {}).get("avg")),
            "strike_rate": _s(d.get("battingStats", {}).get("strikeRate")),
            "hundreds":    _s(d.get("battingStats", {}).get("hundreds")),
            "fifties":     _s(d.get("battingStats", {}).get("fifties")),
            "highest":     _s(d.get("battingStats", {}).get("highestScore")),
        },
        "bowling": {
            "matches":      _s(d.get("bowlingStats", {}).get("matches")),
            "wickets":      _s(d.get("bowlingStats", {}).get("wkts")),
            "economy":      _s(d.get("bowlingStats", {}).get("economy")),
            "average":      _s(d.get("bowlingStats", {}).get("avg")),
            "best_bowling": _s(d.get("bowlingStats", {}).get("bestBowling")),
        },
    }


# ---------------------------------------------------------------------------
# 3. Recent matches
# ---------------------------------------------------------------------------

def get_recent_matches(limit: int = 10) -> dict:
    """
    Fetch recently completed international cricket matches.

    Parameters
    ----------
    limit : int  Max results (default 10, capped at 20).
    """
    limit = max(1, min(int(limit), 20))
    raw = _get("/matches", params={"offset": 0})
    if "error" in raw:
        return raw

    matches = [
        {
            "match_id":   item.get("id", ""),
            "teams":      item.get("name", ""),
            "result":     item.get("status", "Result not available"),
            "date":       item.get("date", ""),
            "match_type": item.get("matchType", "").upper(),
            "venue":      item.get("venue", ""),
        }
        for item in raw.get("data", [])[:limit]
    ]
    return {"matches": matches, "count": len(matches)}


# ---------------------------------------------------------------------------
# 4. Match scorecard
# ---------------------------------------------------------------------------

def get_match_scorecard(match_id: str) -> dict:
    """
    Fetch the full scorecard for a match.

    Parameters
    ----------
    match_id : str  From get_live_scores() or get_recent_matches().
    """
    raw = _get("/match_info", params={"id": match_id})
    if "error" in raw:
        return raw

    d = raw.get("data", {})
    match_info = {
        "teams":      d.get("name", ""),
        "venue":      d.get("venue", ""),
        "date":       d.get("date", ""),
        "match_type": d.get("matchType", "").upper(),
        "status":     d.get("status", ""),
        "toss":       (d.get("tossWinner", "") + " won toss") if d.get("tossWinner") else "",
    }
    innings = [
        {
            "team":    s.get("inning", ""),
            "runs":    s.get("r", 0),
            "wickets": s.get("w", 0),
            "overs":   s.get("o", 0),
        }
        for s in d.get("score", [])
    ]
    return {"match_info": match_info, "innings": innings}
